    def decode_websocket_frame(self, data):
        """Decode WebSocket frame with security checks"""
        if len(data) < 2:
            return None
        
        # Check if frame is masked (client frames must be masked)
        masked = data[1] & 0x80
        if not masked:
            return None  # Reject unmasked frames from client
        
        payload_len = data[1] & 0x7F
        
        if payload_len == 126:
            if len(data) < 4:
                return None
            payload_len = int.from_bytes(data[2:4], 'big')
            mask_start = 4
        elif payload_len == 127:
            if len(data) < 10:
                return None
            payload_len = int.from_bytes(data[2:10], 'big')
            mask_start = 10
        else:
            mask_start = 2
        
        # Limit payload size to prevent DoS
        if payload_len > 4096:
            return None
        
        if len(data) < mask_start + 4 + payload_len:
            return None
        
        mask = data[mask_start:mask_start + 4]
        payload = bytearray(data[mask_start + 4:mask_start + 4 + payload_len])
        
        # Unmask payload
        for i in range(len(payload)):
            payload[i] ^= mask[i % 4]
        
        return bytes(payload)
    
    def encode_websocket_frame(self, data):
        """Encode WebSocket frame"""
        frame = bytearray()
        frame.append(0x81)  # Text frame, FIN bit set
        
        payload = data.encode() if isinstance(data, str) else data
        payload_len = len(payload)
        
